// // This module selects between two inputs based on the control signal
// If sel is 0, out will be equal to b; if sel is 1, out will be equal to a
module mux3(input [2:0] a, input [2:0] b, input sel, output reg [2:0] out);
    always @*
        if (sel == 1'b0)
            out = a;
        else
            out = b;
endmodule
